--
-- Table structure for table `products`
--

DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `products` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(180) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(190) COLLATE utf8mb4_unicode_ci NOT NULL,
  `shortDescription` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` longtext COLLATE utf8mb4_unicode_ci,
  `logo` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `originalPrice` decimal(12,2) NOT NULL DEFAULT '0.00',
  `basePrice` decimal(12,2) NOT NULL DEFAULT '0.00',
  `status` enum('active','inactive') COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  `isFeatured` tinyint(1) DEFAULT '0',
  `isBestSeller` tinyint(1) DEFAULT '0',
  `warrantyDescription` text COLLATE utf8mb4_unicode_ci,
  `usageInstructions` text COLLATE utf8mb4_unicode_ci,
  `terms` text COLLATE utf8mb4_unicode_ci,
  `features` json DEFAULT NULL,
  `badge` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `soldCount` int unsigned DEFAULT '0',
  `viewCount` int unsigned DEFAULT '0',
  `averageRating` decimal(3,2) DEFAULT '0.00',
  `reviewCount` int unsigned DEFAULT '0',
  `seoTitle` varchar(190) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `seoDescription` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `deletedAt` datetime DEFAULT NULL,
  `categoryId` int unsigned NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`),
  KEY `products_slug` (`slug`),
  KEY `products_status` (`status`),
  KEY `products_is_featured` (`isFeatured`),
  KEY `products_is_best_seller` (`isBestSeller`),
  KEY `products_created_at` (`createdAt`),
  KEY `products_category_id_status` (`categoryId`,`status`),
  CONSTRAINT `products_ibfk_1` FOREIGN KEY (`categoryId`) REFERENCES `categories` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=44 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

