LOCK TABLES `products` WRITE;
/*!40000 ALTER TABLE `products` DISABLE KEYS */;
INSERT INTO `products` VALUES (1,'Duolingo','duolingo','Tài khoản Duolingo bản quyền, kích hoạt nhanh, hỗ trợ tận tâm trong suốt thời gian sử dụng.','Duolingo giúp bạn khai thác trọn vẹn các tính năng nâng cao với mức chi phí hợp lý. Sản phẩm được Hải Premium kiểm tra trước khi bàn giao, đi kèm hướng dẫn sử dụng và chính sách bảo hành minh bạch.','/assets/logos/duolingo.png',129000.00,79000.00,'active',0,1,'Bảo hành trong toàn bộ thời hạn gói đối với lỗi từ tài khoản hoặc quá trình kích hoạt. Không bảo hành trường hợp khách hàng tự thay đổi thông tin trái hướng dẫn.','Đăng nhập bằng thông tin được bàn giao. Không thay đổi email, mật khẩu hoặc thông tin khôi phục nếu loại gói không cho phép. Liên hệ hỗ trợ khi gặp lỗi.','Chỉ sử dụng cho nhu cầu hợp pháp và tuân thủ điều khoản của nhà cung cấp dịch vụ. Không chia sẻ lại thông tin tài khoản cho bên thứ ba.','[\"Truy cập đầy đủ tính năng Premium\", \"Hỗ trợ học tập trên nhiều thiết bị\", \"Hướng dẫn kích hoạt rõ ràng\", \"Bảo hành trong thời gian sử dụng\"]','Bán chạy',1260,2268,4.90,202,'Duolingo giá tốt | Hải Premium','Tài khoản Duolingo bản quyền, kích hoạt nhanh, hỗ trợ tận tâm trong suốt thời gian sử dụng.','2026-07-12 19:46:41','2026-07-12 19:46:41',NULL,1),(2,'ELSA Speak','elsa-speak','Tài khoản ELSA Speak bản quyền, kích hoạt nhanh, hỗ trợ tận tâm trong suốt thời gian sử dụng.','ELSA Speak giúp bạn khai thác trọn vẹn các tính năng nâng cao với mức chi phí hợp lý. Sản phẩm được Hải Premium kiểm tra trước khi bàn giao, đi kèm hướng dẫn sử dụng và chính sách bảo hành minh bạch.','/assets/logos/elsa.png',249000.00,149000.00,'active',0,0,'Bảo hành trong toàn bộ thời hạn gói đối với lỗi từ tài khoản hoặc quá trình kích hoạt. Không bảo hành trường hợp khách hàng tự thay đổi thông tin trái hướng dẫn.','Đăng nhập bằng thông tin được bàn giao. Không thay đổi email, mật khẩu hoặc thông tin khôi phục nếu loại gói không cho phép. Liên hệ hỗ trợ khi gặp lỗi.','Chỉ sử dụng cho nhu cầu hợp pháp và tuân thủ điều khoản của nhà cu